namespace BgControls.Windows.Controls;/// <summary>/// 指定选项卡控件（TabControl）在滚动时的计算模式./// </summary>public enum TabControlScrollMode{    /// <summary>    /// 像素滚动模式. 滚动操作以像素为单位进行，提供平滑的滚动效果.    /// </summary>    Pixel,    /// <summary>    /// 项滚动模式. 每次滚动操作以一个完整的选项卡项为单位进行跳转.    /// </summary>    Item,    /// <summary>    /// 视口滚动模式. 每次滚动操作以当前可视区域（视口）的大小为单位进行滚动.    /// </summary>    Viewport,}